import React, { useEffect, useState } from 'react';
import { GlobalSwgSelector } from '../../../../assets/icons/global/GlobalSwgSelector';
import s from './ThisDay.module.scss';
import axios from 'axios';
import { Weather } from '../../../../store/types/types';


interface Props {
  weather: Weather;
}

export const ThisDay = ({ weather }: Props) => {


  
    return (
  <div className={s.thisday}>
     <div className={s.top_block}>        
    <div className={s.top_block_wrapper}>  <div className={s.this_temp}>{weather.weather.main}</div>
       <div className={s.this_day_name}>Сегодня</div></div>
       <GlobalSwgSelector id='sun' />
      </div>
     <div className={s.bottom_block}> 
     <div className={s.this_city}>
       Город: <span>Алматы</span>
     </div>
  </div>
  </div>
  );
};
